export type PublicCommandName = typeof PUBLIC_COMMAND_NAMES[number];
export type RuntimeHealthCheck = typeof RUNTIME_HEALTH_REQUIRED[number];
export type ReadinessMode = keyof typeof READINESS_REQUIRED_BY_MODE;
